import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import response from './response.json';

interface ClassSchedule {
  subject: string;
  startTime: string;
  endTime: string;
  room: string;
  countdownToNext?: string;
}

interface ClassData {
  currentDay: string;
  classesToday: ClassSchedule[];
}

export default function Widget() {
  const classData = response.data as ClassData;
  const { currentDay, classesToday } = classData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FBBF24' }}>
              {response.widget.app}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Schedule for {currentDay}
            </Typography>
          </Box>

          {classesToday.map((classItem, index) => (
            <Box key={index}>
              {index > 0 && <Divider sx={{ my: 1 }} />}
              <Stack spacing={1}>
                <Typography variant="body1" sx={{ color: '#F8FAFC', fontWeight: 500 }}>
                  {classItem.subject}
                </Typography>
                <Stack direction="row" spacing={0.5}>
                  <Chip label={classItem.startTime} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#3B82F6', color: '#F8FAFC' }} />
                  <Chip label={classItem.endTime} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#3B82F6', color: '#F8FAFC' }} />
                  <Chip label={`Room: ${classItem.room}`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#3B82F6', color: '#F8FAFC' }} />
                </Stack>
                {classItem.countdownToNext && (
                  <Typography variant="caption" color="text.secondary">
                    Starts in {classItem.countdownToNext}
                  </Typography>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
